import{Logger}from '../shared/logger.js';const _debug=(message)=>{};export class ExportManager{static toCSV(data,filename='export.csv',options={}){if(!data||data.length===0){_debug('[Export] No data to export');return;}const{delimiter=',',quote='"',escapeQuote='""',includeBOM=true}=options;const headers=Object.keys(data[0]);let csv='';if(includeBOM){csv+='\uFEFF';}csv+=headers.map(h=>`${quote}${h}${quote}`).join(delimiter)+'\n';data.forEach(row=>{const values=headers.map(header=>{let value=row[header];if(value===null||value===undefined){value='';}value=String(value);value=value.replace(new RegExp(quote,'g'),escapeQuote);if(value.includes(delimiter)||value.includes(quote)||value.includes('\n')){value=`${quote}${value}${quote}`;}return value;});csv+=values.join(delimiter)+'\n';});this.downloadFile(csv,filename,'text/csv;charset=utf-8;');}static toJSON(data,filename='export.json',options={}){const{pretty=true,indent=2}=options;const json=pretty ? JSON.stringify(data,null,indent): JSON.stringify(data);this.downloadFile(json,filename,'application/json;charset=utf-8;');}static tableToCSV(table,filename='table-export.csv'){const tableEl=typeof table==='string' ? document.querySelector(table): table;if(!tableEl){_debug('[Export] Table not found');return;}const rows=tableEl.querySelectorAll('tr');const csvRows=[];rows.forEach(row=>{const cells=row.querySelectorAll('th,td');const values=Array.from(cells).map(cell=>{let text=cell.textContent.trim();const spans=cell.querySelectorAll('span');if(spans.length>0){text=spans[0].textContent.trim();}text=text.replace(/"/g,'""');if(text.includes(',')||text.includes('\n')||text.includes('"')){text=`"${text}"`;}return text;});csvRows.push(values.join(','));});const csv=csvRows.join('\n');this.downloadFile(csv,filename,'text/csv;charset=utf-8;');}static toPDF(element,filename='export.pdf',options={}){const el=typeof element==='string' ? document.querySelector(element): element;if(!el){_debug('[Export] Element not found');return;}const printWindow=window.open('','_blank');const styles=Array.from(document.styleSheets).map(sheet=>{try{return Array.from(sheet.cssRules).map(rule=>rule.cssText).join('\n');}catch(e){return '';}}).join('\n');printWindow.document.write(`<!DOCTYPE html><html><head><title>${filename}</title><style>${styles}@media print{body{padding: 20px;}.no-print{display: none;}}</style></head><body>${el.outerHTML}<script>window.onload=function(){window.print();};</script></body></html>`);printWindow.document.close();}static toExcel(data,filename='export.xlsx',sheetName='Sheet1'){Logger.warn('[Export] Excel export using CSV format. Include SheetJS for true XLSX.');this.toCSV(data,filename.replace('.xlsx','.csv'));}static toPNG(canvas,filename='chart.png',options={}){const canvasEl=typeof canvas==='string' ? document.querySelector(canvas): canvas;if(!canvasEl){_debug('[Export] Canvas not found');return;}const{mimeType='image/png',quality=1.0,scale=2}=options;const tempCanvas=document.createElement('canvas');const ctx=tempCanvas.getContext('2d');tempCanvas.width=canvasEl.width*scale;tempCanvas.height=canvasEl.height*scale;ctx.scale(scale,scale);ctx.drawImage(canvasEl,0,0);const link=document.createElement('a');link.download=filename;link.href=tempCanvas.toDataURL(mimeType,quality);link.click();}static downloadFile(content,filename,mimeType){const blob=new Blob([content],{type: mimeType});const url=URL.createObjectURL(blob);const link=document.createElement('a');link.href=url;link.download=filename;link.style.display='none';document.body.appendChild(link);link.click();document.body.removeChild(link);URL.revokeObjectURL(url);_debug(`[Export] Downloaded: ${filename}`);}static exportFilteredData(config){const{data,filters={},columns=[],filename='filtered-export.csv',format='csv'}=config;let filteredData=[...data];Object.entries(filters).forEach(([key,value])=>{if(value!==null&&value!==undefined&&value!==''){filteredData=filteredData.filter(row=>{const rowValue=row[key];if(Array.isArray(value)){return value.includes(rowValue);}else if(typeof value==='object'){const{min,max}=value;if(min!==null&&rowValue<min)return false;if(max!==null&&rowValue>max)return false;return true;}else{return String(rowValue).includes(String(value));}});}});let exportData=filteredData;if(columns.length>0){exportData=filteredData.map(row=>{const filteredRow={};columns.forEach(col=>{filteredRow[col]=row[col];});return filteredRow;});}if(format==='csv'){this.toCSV(exportData,filename);}else if(format==='json'){this.toJSON(exportData,filename);}}static createExportButton(tableSelector,options={}){const{formats=['csv','json'],position='top-right',buttonClass='export-btn'}=options;const container=document.createElement('div');container.className=`export-container export-${position}`;const select=document.createElement('select');select.className=buttonClass;select.innerHTML=`<option value="">Export...</option>${formats.map(f=>`<option value="${f}">As ${f.toUpperCase()}</option>`).join('')}`;select.addEventListener('change',(e)=>{const format=e.target.value;if(!format)return;const table=document.querySelector(tableSelector);const filename=`export-${new Date().toISOString().split('T')[0]}.${format}`;if(format==='csv'){this.tableToCSV(table,filename);}else if(format==='json'){const data=this.tableToJSON(table);this.toJSON(data,filename);}e.target.value='';});container.appendChild(select);return container;}static tableToJSON(table){const rows=table.querySelectorAll('tr');const headers=Array.from(rows[0].querySelectorAll('th,td')).map(h=>h.textContent.trim());const data=[];for(let i=1;i<rows.length;i++){const row=rows[i];const cells=row.querySelectorAll('td');if(cells.length>0){const rowData={};headers.forEach((header,index)=>{rowData[header]=cells[index]?.textContent.trim()||'';});data.push(rowData);}}return data;}}export default ExportManager;if(typeof window!=='undefined'){window.ExportManager=ExportManager;}